#include <stdio.h>
int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        long long X; scanf("%lld", &X);
        if (X >= 12) printf("Yes\n");
        else printf("No\n");
    }
    return 0;
}

